import uniCollapse from '@/components/uni-collapse/uni-collapse.vue';
import uniCollapseItem from '@/components/uni-collapse-item/uni-collapse-item.vue';
import wPicker from '@/components/w-picker/w-picker.vue';
import qiniuUploader from '@/common/qiniuUploader.js';
export default {
	data() {
		return {
			showShareMask: false,
			listData: [
				{
					type: false,
					subName: '',
					content: ''
				}
			],
			id: '',
			modalName: null,
			customerData: '',
			TabCur: 0,
			tabSelects: ['基本资料', '客户跟进'],
			imgList: [],
			recordList: [], //跟进记录
			recordType: ['当面拜访', '电话拜访', '聊天软件拜访', '其他'], //1-当面拜访,2-电话拜访,3-聊天软件拜访,4-其他
			formData: {
				visit_type: 0,
				c_time: 0,
				resistance_point: '',
				agree_point: '',
				suggest_point: '',
				attribution: '',
				transaction_point: '',
				extend: ''
			},
			cTime: '',
			PtemplateList: '', //录入客户模板
			imgList: [],
			qiniuDatas: '',
			visit_type: 0,
			groupSaleData: '',
			shareDatas:'',
			share_ids:''
		};
	},
	components: {
		uniCollapse,
		uniCollapseItem,
		wPicker
	},
	onLoad(option) {
		this.id = option.id;
		// this.id = '259496';
		this.getCustomerInfo();
		this.getQiniuToken();
	},
	computed: {
		nowDay() {
			let date = new Date();
			return date.getFullYear() + '' + (date.getMonth() + 1) + '' + date.getDate();
		}
	},
	methods: {
		onShares(data) {
			this.$refs.sharePersons.close();
			let ids = [];
			let names = [];
			if (data) {
				data.forEach(res => {
					ids.push(res.u_id);
					names.push(res.u_name);
				});
			}
			this.customerData.share_name = this.$tools.toStrings(names);
			this.share_ids = this.$tools.toStrings(ids);
			this.setShare();
		},
		update(){
			this.$store.commit('setCustomerInfo',this.customerData);
			uni.navigateTo({
				url:'/pages/customer/customer_update?id='+this.id
			})
		},
		setShare(){
			if(this.shareDatas){
				this.$api.SetSharecustomapi({id:this.id,share_str:this.share_ids},res =>{
					if(res.code == 1000){
						this.getCustomerInfo();
						this.showShareMask = !this.showShareMask;
					}
				})
			}
			
		},
		checkboxChange(e) {
			let values = e.detail.value;
			this.shareDatas = values;
			if(values.length < 6){
				for (let x in this.groupSaleData) {
					for (var i = 0, lenI = this.groupSaleData[x].length; i < lenI; ++i) {
						  this.groupSaleData[x][i].checked = false;
						for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
							if (this.groupSaleData[x][i].u_id + '1' == values[j]) {
								this.groupSaleData[x][i].checked = true;
								this.$forceUpdate();
								break;
							}
						}
					}
				}
			}else{
				uni.showToast({
					icon:'none',
					title:'最多只能有五个共享人'
				})
			}
			
		},
		stop() {},
		showShare() {
			if(this.customerData.edit_status == 1){
				if (this.groupSaleData) {
					this.$refs.sharePersons.open();
				} else {
					uni.showToast({
						icon: 'none',
						title: '此项目无共享人'
					});
				}
			}
		},
		PickerChange(e) {
			this.visit_type = e.detail.value;
		},
		getQiniuToken() {
			uni.showLoading({
				title: '正在获取数据...'
			});
			this.$api.qiniuTokencustomapi({}, res => {
				this.qiniuDatas = res;
			});
		},
		ViewImages(item, index) {
			uni.previewImage({
				urls: item,
				current: index
			});
		},
		ViewImage(e) {
			uni.previewImage({
				urls: this.imgList,
				current: e.currentTarget.dataset.url
			});
		},
		DelImg(e) {
			uni.showModal({
				title: '提示',
				content: '确定删除？',
				cancelText: '取消',
				confirmText: '确定',
				success: res => {
					if (res.confirm) {
						this.imgList.splice(e.currentTarget.dataset.index, 1);
					}
				}
			});
		},
		ChooseImage() {
			uni.chooseImage({
				count: 3, //默认9
				sizeType: ['original', 'compressed'], //可以指定是原图还是压缩图，默认二者都有
				sourceType: ['album'], //从相册选择
				success: res => {
					if (this.imgList.length != 0) {
						this.imgList = this.imgList.concat(res.tempFilePaths);
					} else {
						this.imgList = res.tempFilePaths;
					}
				}
			});
		},
		chooseTemp(item, index, items) {
			item.index = index;
			//0 select 单选  1 check-box  复选 2 radio单选
			if (items.type == 1) {
				item.active = !item.active;
			} else {
				items.list.forEach(res => {
					res.active = false;
				});
				item.active = !item.active;
			}
			this.$forceUpdate();
		},
		onConfirm(res) {
			//时间选择
			this.cTime = res.result;
			this.formData.c_time = this.$tools.timeToTimeStamp(res.result);
		},
		showTimes() {
			this.$refs.dateTime.show();
		},
		getPTemplate() {
			let data = {
				pid: this.customerData.pid,
				type: 2 //1：录入客户模板；2：跟进客户模板
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojecttemplatecustomapi(data, res => {
				this.PtemplateList = [];
				for (let var1 in res.data) {
					let temp = {
						name: res.data[var1].title,
						list: [],
						key: var1,
						idIndex: 0,
						empty: res.data[var1].empty, ////是否必选（1-非必选，2-必选）
						type: res.data[var1].type, //0 select 单选  1 check-box  复选 2 radio单选
						enable: res.data[var1].enable //是否启用（1-启用，2-禁用）
					};
					res.data[var1].option_data.forEach(res => {
						let datas = {
							name: res,
							active: false
						};
						temp.list.push(datas);
					});
					this.PtemplateList.push(temp);
				}
			});
		},
		showHeadImg(img) {
			let imgs = [];
			imgs.push(img);
			uni.previewImage({
				urls: imgs,
				current: 0
			});
		},
		call(tel) {
			if (tel) {
				let tels = this.$tools.isPhone(tel);
				if (tels) {
					uni.showModal({
						content: '是否拨打电话？',
						success(e) {
							if (e.confirm) {
								uni.makePhoneCall({
									phoneNumber: tel
								});
							}
						}
					});
				}
			}
		},
		change(e) {
			//console.log(e)
		},
		cName(names) {
			if (names.length > 2) {
				let m = names.length;
				return names.substring(m - 2, m);
			} else {
				return names;
			}
		},
		tabSelect(e) {
			this.TabCur = e.currentTarget.dataset.id;
		},
		getCustomerInfo() {
			let data = {
				id: this.id
			};
			this.$api.getInfocustomapi(data, res => {
				this.customerData = res.data;
				this.getPTemplate();
				this.getGroupsale();
			});
			this.getRecordapi();
		},
		getGroupsale() {
			this.$api.GetGroupsalecustomapi({pid:this.customerData.pid},res =>{
				if(res.code ==1000){
					this.groupSaleData = res.data;
					this.$store.commit('setGroupSaleData',this.groupSaleData );
				}else{
					uni.showToast({
						icon:'none',
						title:res.msg
					})
				}
				
			});
		},
		ViewImage(e) {
			uni.previewImage({
				urls: this.customerData.photo,
				current: e.currentTarget.dataset.url
			});
		},
		//客户跟进记录
		getRecordapi() {
			let data = {
				id: this.id
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.indexRecordapi(data, res => {
				if(res.code ==1000){
					this.recordList = res.data.data;
				}else{
					uni.showToast({
						icon:'none',
						title:res.msg
					})
				}
			});
		},
		addRecord() {
			this.TabCur = 2;
		},
		imageUploads() {
			let _this = this;
			return new Promise(resolve => {
				let keys = [];
				let token = this.qiniuDatas.token;
				let domain = this.qiniuDatas.http_domain;
				let bucket = this.qiniuDatas.bucket;
				_this.imgList.forEach(filePath => {
					let key = 'sunest-' + this.nowDay + '-' + new Date().getTime() + '.jpg';
					keys.push(key);
					qiniuUploader.upload(
						filePath,
						res => {
							// console.log('ressss: ' + JSON.stringify(res));
						},
						error => {
							// resolve(error)
						},
						{
							region: 'SCN', // ECN, SCN, NCN, NA, ASG，分别对应七牛的：华东，华南，华北，北美，新加坡 5 个区域
							domain: domain, // // bucket 域名，下载资源时用到。如果设置，会在 success callback 的 res 参数加上可以直接使用的 ImageURL 字段。否则需要自己拼接
							key: key, // [非必须]自定义文件 key。如果不设置，默认为使用微信小程序 API 的临时文件名
							// 以下方法三选一即可，优先级为：uptoken > uptokenURL > uptokenFunc
							uptoken: token // 由其他程序生成七牛 uptoken
						},
						res => {
							if (res.progress === 100) {
								resolve(keys);
							}
						}
					);
				});
			});
		},
		async sub() {
			this.formData.extend = [];
			this.formData.id = this.customerData.id;
			if (!this.formData.c_time) {
				uni.showToast({
					icon: 'none',
					title: '请选择跟进时间'
				});
				return;
			}
			this.formData.visit_type = this.visit_type + 1;
			let obj = {};
			for (let var1 in this.PtemplateList) {
				let keyValue = {};
				let key = this.PtemplateList[var1].key;
				keyValue[key] = [];
				this.PtemplateList[var1].list.forEach(resp => {
					if (resp.active == true) {
						keyValue[key].push(resp.index);
					}
				});
				if (keyValue[key].length == 0 && this.PtemplateList[var1].empty == 2) {
					uni.showToast({
						icon: 'none',
						title: this.PtemplateList[var1].name + '必须选择'
					});
					return;
				}
				obj[key] = keyValue[key];
			}

			this.formData.extend = obj;
			uni.showLoading({
				title: '正在上传数据...'
			});
			this.formData.image = ''; //七牛云图片名
			if (this.imgList.length !== 0) {
				try {
					this.formData.image = await this.imageUploads();
				} catch (e) {
					//TODO handle the exception
				}
			}
			this.$api.AddRecordapi(this.formData, res => {
				if (res.code == 1000) {
					this.TabCur = 1;
					this.getRecordapi();
				} else {
					uni.showToast({
						icon: 'none',
						title: res.msg
					});
				}
			});
		}
	}
};
